import type { FC } from "react";

import { cn } from "../../lib/ui/cn";

interface Step {
  label: string;
}

interface StepperProps {
  steps: Step[];
  currentStep: number;
  className?: string;
}

export const Stepper: FC<StepperProps> = ({
  steps,
  currentStep,
  className,
}) => (
  <div className={cn("flex items-center justify-center gap-px", className)}>
    {steps.map((step, index) => {
      const stepNumber = index + 1;
      const isActive = stepNumber <= currentStep;

      return (
        <div key={stepNumber} className="flex items-center gap-px">
          <div
            className={cn(
              "flex items-end gap-[9px]",
              !isActive && "opacity-50",
            )}
          >
            <div className="flex size-6 items-center justify-center rounded-xl bg-primary">
              <span className="font-normal font-sans text-white text-xs leading-[1.66em] tracking-[0.033em]">
                {stepNumber}
              </span>
            </div>
            <span className="font-bold font-serif text-foreground text-lg leading-[1.199em]">
              {step.label}
            </span>
          </div>

          {index < steps.length - 1 && (
            <div className="flex w-20 items-center px-2.5">
              <div className="h-px w-full bg-primary" />
            </div>
          )}
        </div>
      );
    })}
  </div>
);

