file.content:
const getStepColor = (stepId: number) => {
  if ((isClosed || isPaidOut) && stepId <= activeStep) return "bg-[#047857]";

  if (isUnsettled) {
    if (stepId < activeStep) return "bg-[#047857]";
    if (stepId === activeStep) return "bg-[#B91C1C]";
    return "bg-stone-400";
  }

  if (stepId < activeStep) return "bg-[#047857]";
  if (stepId === activeStep) {
    if (isRejected) return "bg-[#B91C1C]";
    return "bg-[#00158A]";
  }
  return "bg-stone-400";
};

const getActiveStepText = () => {
  if (isUnsettled) {
    return dueDate ? `Expired: ${formatDate(dueDate)}` : "Expired";
  }

  if (isRejected) {
    const rejectedTimestamp = getTimestampForStep(activeStep);
    const isExpired = EXPIRED_STATUSES.includes(currentStatus);
    const label = isExpired ? "Offer Expired" : "Item Declined";
    if (rejectedTimestamp)
      return `${label}: ${formatDate(rejectedTimestamp)}`;
    return label;
  }

  if (activeStep === 1) {
    const stepTimestamp = getTimestampForStep(1);
    if (stepTimestamp) return `Submitted: ${formatDate(stepTimestamp)}`;
  }

  if (activeStep === 2) return "Reply soon: 48 hours left";

  if (activeStep === 3) {
    const acceptEvent = eventsLog?.find(
      (e) => e.status === BuybackRequestStatus.PreAuthOfferAccepted
    );
    if (acceptEvent) {
      const deadline = new Date(acceptEvent.timestamp);
      deadline.setDate(deadline.getDate() + 2);
      return `Submit by: ${formatDate(deadline)}`;
    }
    return "Preparation for shipment";
  }

