1	"use client";
2	
3	import { formatDate } from "@/shared/lib/utils/format-date";
4	import {
5	  type BuybackRequestEvent,
6	  BuybackRequestStatus,
7	} from "@/shared/types/buyback-request.types";
8	import {
9	  Accordion,
10	  AccordionContent,
11	  AccordionItem,
12	  AccordionTrigger,
13	} from "@/shared/ui/shadcn/accordion";
14	import { useMemo } from "react";
15	
16	interface Step {
17	  id: number;
18	  label: string;
19	  statuses: BuybackRequestStatus[];
20	}
21	
22	export const STEPS: Step[] = [
23	  {
24	    id: 1,
25	    label: "Request in Review",
26	    statuses: [
27	      BuybackRequestStatus.New,
28	      BuybackRequestStatus.PendingValuation,
29	      BuybackRequestStatus.ValuationReceived,
30	    ],
31	  },
32	  {
33	    id: 2,
34	    label: "Indicative Offer Approval",
35	    statuses: [
36	      BuybackRequestStatus.PreAuthOfferSent,
37	      BuybackRequestStatus.PreAuthVerificationFailed,
38	      BuybackRequestStatus.RejectedPreAuthOffer,
39	      BuybackRequestStatus.PreAuthOfferExpired,
40	    ],
41	  },
42	  {
43	    id: 3,
44	    label: "Item Reception",
45	    statuses: [BuybackRequestStatus.PreAuthOfferAccepted],
46	  },
47	  {
48	    id: 4,
49	    label: "Final Offer Approval",
50	    statuses: [
51	      BuybackRequestStatus.AssetReceived,
52	      BuybackRequestStatus.FinalOfferSent,
53	      BuybackRequestStatus.PendingAuth,
54	      BuybackRequestStatus.AuthCompleted,
55	      BuybackRequestStatus.PendingEntrupy,
56	      BuybackRequestStatus.KycPending,
57	      BuybackRequestStatus.KycApproved,
58	      BuybackRequestStatus.PostAuthVerificationFailed,
59	      BuybackRequestStatus.KYCFailed,
60	      BuybackRequestStatus.RejectedPostAuthOffer,
61	      BuybackRequestStatus.PostAuthOfferExpired,
62	    ],
63	  },
64	  {
65	    id: 5,
66	    label: "Buyback Activation",
67	    statuses: [BuybackRequestStatus.TransactionPending],
68	  },
69	  {
70	    id: 6,
71	    label: "Buyback Payment",
72	    statuses: [BuybackRequestStatus.FinalOfferAccepted],
73	  },
74	];
75	
76	const REJECTED_STATUSES = [
77	  BuybackRequestStatus.PreAuthVerificationFailed,
78	  BuybackRequestStatus.PostAuthVerificationFailed,
79	  BuybackRequestStatus.KYCFailed,
80	  BuybackRequestStatus.RejectedPreAuthOffer,
81	  BuybackRequestStatus.RejectedPostAuthOffer,
82	  BuybackRequestStatus.PreAuthOfferExpired,
83	  BuybackRequestStatus.PostAuthOfferExpired,
84	];
85	
86	const EXPIRED_STATUSES = [
87	  BuybackRequestStatus.PreAuthOfferExpired,
88	  BuybackRequestStatus.PostAuthOfferExpired,
89	];
90	
91	interface BuybackDetailsStepperProps {
92	  currentStatus: BuybackRequestStatus;
93	  eventsLog?: BuybackRequestEvent[];
94	  dueDate?: string;
95	  fundedOn?: string;
96	  isPaidOut?: boolean;
97	  paidData?: string;
98	  isClosed?: boolean;
99	  isUnsettled?: boolean;
100	  closeData?: string;
101	}
102	
103	export const BuybackDetailsStepper = ({
104	  currentStatus,
105	  eventsLog,
106	  dueDate,
107	  fundedOn,
108	  isClosed,
109	  isUnsettled,
110	  isPaidOut,
111	  paidData,
112	  closeData,
113	}: BuybackDetailsStepperProps) => {
114	  const activeStep = useMemo(() => {
115	    if (isClosed || isUnsettled || isPaidOut) return 6;
116	    const step = STEPS.find((s) => s.statuses.includes(currentStatus));
117	    return step ? step.id : 1;
118	  }, [currentStatus, isClosed, isUnsettled, isPaidOut]);
119	
120	  const isRejected = REJECTED_STATUSES.includes(currentStatus);
121	  const currentStepData = STEPS.find((s) => s.id === activeStep) || STEPS[0];
122	
123	  const getTimestampForStep = (stepId: number) => {
124	    if (!eventsLog) return null;
125	    const stepDef = STEPS.find((s) => s.id === stepId);
126	    if (!stepDef) return null;
127	
128	    const relevantLogs = eventsLog
129	      .filter((log) =>
130	        stepDef.statuses.includes(log.status as BuybackRequestStatus)
131	      )
132	      .sort(
133	        (a, b) =>
134	          new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()
135	      );
136	
137	    return relevantLogs[0]?.timestamp || null;
138	  };
139	
140	  const getStepColor = (stepId: number): string => {
141	    if ((isClosed || isPaidOut) && stepId <= activeStep) return "#047857";
142	
143	    if (isUnsettled) {
144	      if (stepId < activeStep) return "#047857";
145	      if (stepId === activeStep) return "#B91C1C";
146	      return "#a8a29e";
147	    }
148	
149	    if (stepId < activeStep) return "#047857";
150	    if (stepId === activeStep) {
151	      if (isRejected) return "#B91C1C";
152	      return "#00158A";
153	    }
154	    return "#a8a29e";
155	  };
156	
157	  const getActiveStepText = () => {
158	    if (isUnsettled) {
159	      return dueDate ? `Expired: ${formatDate(dueDate)}` : "Expired";
160	    }
161	
162	    if (isRejected) {
163	      const rejectedTimestamp = getTimestampForStep(activeStep);
164	      const isExpired = EXPIRED_STATUSES.includes(currentStatus);
165	      const label = isExpired ? "Offer Expired" : "Item Declined";
166	      if (rejectedTimestamp)
167	        return `${label}: ${formatDate(rejectedTimestamp)}`;
168	      return label;
169	    }
170	
171	    if (activeStep === 1) {
172	      const stepTimestamp = getTimestampForStep(1);
173	      if (stepTimestamp) return `Submitted: ${formatDate(stepTimestamp)}`;
174	    }
175	
176	    if (activeStep === 2) return "Reply soon: 48 hours left";
177	
178	    if (activeStep === 3) {
179	      const acceptEvent = eventsLog?.find(
180	        (e) => e.status === BuybackRequestStatus.PreAuthOfferAccepted
181	      );
182	      if (acceptEvent) {
183	        const deadline = new Date(acceptEvent.timestamp);
184	        deadline.setDate(deadline.getDate() + 2);
185	        return `Submit by: ${formatDate(deadline)}`;
186	      }
187	      return "Preparation for shipment";
188	    }
189	
190	    if (activeStep === 4) {
191	      if (currentStatus === BuybackRequestStatus.FinalOfferSent)
192	        return "Reply soon: 48 hours left";
193	      const received = eventsLog?.find(
194	        (e) => e.status === BuybackRequestStatus.AssetReceived
195	      );
196	      if (received) return `Received: ${formatDate(received.timestamp)}`;
197	      return "Processing item...";
198	    }
199	
200	    if (activeStep === 5) {
201	      if (currentStatus === BuybackRequestStatus.TransactionPending) {
202	        return "Transaction Pending";
203	      }
204	
205	      return fundedOn
206	        ? `Funded: ${formatDate(fundedOn)}`
207	        : "Processing payment...";
208	    }
209	
210	    if (activeStep === 6) {
211	      if (isClosed && closeData) {
212	        return `Closed: ${formatDate(closeData)}`;
213	      }
